import{_ as t,N as i,o as l,a as r,e as n,i as s}from"./chunks/framework.DW6Cm6Mn.js";const f=JSON.parse('{"title":"À propos de Vala","description":"Vala est un langage de programmation orienté objet avec un compilateur qui génère du code C et utilise le système de type GObject.","frontmatter":{"title":"À propos de Vala","description":"Vala est un langage de programmation orienté objet avec un compilateur qui génère du code C et utilise le système de type GObject."},"headers":[],"relativePath":"fr/about/index.md","filePath":"fr/about/index.md"}'),o={name:"fr/about/index.md"};function d(u,e,c,p,m,h){const a=i("PredefinedCtaStack");return l(),r("div",null,[e[0]||(e[0]=n('<h1 id="a-propos-de-vala" tabindex="-1">À propos de Vala <a class="header-anchor" href="#a-propos-de-vala" aria-label="Permalink to &quot;À propos de Vala&quot;">​</a></h1><h2 id="qu-est-ce-que-vala" tabindex="-1">Qu&#39;est-ce que Vala ? <a class="header-anchor" href="#qu-est-ce-que-vala" aria-label="Permalink to &quot;Qu&#39;est-ce que Vala ?&quot;">​</a></h2><p>Vala est un langage de programmation orienté objet avec un compilateur qui génère du code C et utilise le système de type GObject.</p><p>Vala prend en charge les fonctionnalités de langage moderne telles que :</p><ul><li>Interfaces</li><li>Properties</li><li>Signals</li><li>Foreach statements</li><li>Lambda expressions</li><li>Type inferencing for local variables</li><li>Generics</li><li>Non-null types</li><li>Assisted memory management</li><li>Exception handling</li><li>Type modules (Plugins)</li></ul><h2 id="quel-genre-de-langue-est-vala" tabindex="-1">Quel genre de langue est Vala? <a class="header-anchor" href="#quel-genre-de-langue-est-vala" aria-label="Permalink to &quot;Quel genre de langue est Vala?&quot;">​</a></h2><h3 id="productif" tabindex="-1">Productif <a class="header-anchor" href="#productif" aria-label="Permalink to &quot;Productif&quot;">​</a></h3><p>Avec Vala, vous pouvez être opérationnel rapidement, grâce à des fonctionnalités pratiques telles que les expressions lambda, la gestion des exceptions, les interfaces et les génériques.</p><h3 id="performant" tabindex="-1">Performant <a class="header-anchor" href="#performant" aria-label="Permalink to &quot;Performant&quot;">​</a></h3><p>Le code Vala se compile en binaires entièrement natifs.</p><h3 id="statically-typed" tabindex="-1">Statically-Typed <a class="header-anchor" href="#statically-typed" aria-label="Permalink to &quot;Statically-Typed&quot;">​</a></h3><p>Vala vous aide à écrire du code de type sécurisé sans verbosité, grâce à l&#39;inférence de type.</p><h3 id="integrative" tabindex="-1">Integrative <a class="header-anchor" href="#integrative" aria-label="Permalink to &quot;Integrative&quot;">​</a></h3><p>Vala est conçu pour permettre l&#39;accès aux bibliothèques C existantes, en particulier les bibliothèques basées sur GObject, sans avoir besoin de liaisons d&#39;exécution. Tout ce qui est nécessaire pour utiliser une bibliothèque avec Vala est un fichier vapi, contenant les déclarations de classe et de méthode dans la syntaxe Vala. Vala est actuellement livré avec des liaisons pour GLib et GTK + et bien d&#39;autres de la plate-forme GNOME.</p><p>Vala peut également être utilisé pour créer des bibliothèques C.</p><h3 id="familiar" tabindex="-1">Familiar <a class="header-anchor" href="#familiar" aria-label="Permalink to &quot;Familiar&quot;">​</a></h3><p>La syntaxe de Vala est inspirée de C # et Java, donc si vous avez utilisé l&#39;un ou l&#39;autre, vous vous adapterez de manière transparente à l&#39;écriture de code Vala.</p>',17)),s(a)])}const g=t(o,[["render",d]]);export{f as __pageData,g as default};
